import{_ as o,c as a,o as t,a5 as i,dE as n,dF as r,dG as l,dH as d,dI as c,dJ as s,dK as m,dL as u,dM as p,dN as h,dO as b,dP as f,dQ as g,dR as _,dS as k}from"./chunks/framework.Dm71djiW.js";const T=JSON.parse('{"title":"Quick Formula Editing","description":"","frontmatter":{"title":"Quick Formula Editing"},"headers":[],"relativePath":"docs/guide-equation.md","filePath":"docs/guide-equation.md","lastUpdated":1772675768000}'),q={name:"docs/guide-equation.md"};function M(y,e,E,x,P,I){return t(),a("div",null,[...e[0]||(e[0]=[i('<h1 id="quick-formula-editing" tabindex="-1">Quick Formula Editing <a class="header-anchor" href="#quick-formula-editing" aria-label="Permalink to “Quick Formula Editing”">​</a></h1><p>Liii STEM has a dedicated <strong>Math Mode</strong> for formula <strong>editing</strong>, <strong>numbering</strong>, and <strong>cross-referencing</strong>. It also integrates efficient features such as LEGO symbols, Tab cycling, and Magic Paste to speed up math writing.</p><h2 id="what-is-math-mode" tabindex="-1">What Is Math Mode <a class="header-anchor" href="#what-is-math-mode" aria-label="Permalink to “What Is Math Mode”">​</a></h2><p>Math Mode in Liii STEM provides complete math environments. Any math-related content should be entered in Math Mode.</p><p>In text mode, the mode toolbar mainly contains text-environment actions (for example, inserting sections). In Math Mode, the mode toolbar provides more mathematical symbols.</p><p>The image below shows the toolbar in different modes (default theme):</p><p><img src="'+n+'" alt=""></p><h2 id="enter-math-mode" tabindex="-1">Enter Math Mode <a class="header-anchor" href="#enter-math-mode" aria-label="Permalink to “Enter Math Mode”">​</a></h2><h3 id="use-the-mode-toolbar" tabindex="-1">Use the mode toolbar <a class="header-anchor" href="#use-the-mode-toolbar" aria-label="Permalink to “Use the mode toolbar”">​</a></h3><p>In text mode, click the <code>π</code> button in the mode toolbar, then choose inline formula, single-line formula, or multi-line formula.</p><p><img src="'+r+'" alt=""></p><blockquote><p>Inline formula</p></blockquote><p><img src="'+l+'" alt=""></p><blockquote><p>Single-line formula</p></blockquote><p><img src="'+d+'" alt=""></p><blockquote><p>Multi-line formula</p></blockquote><h3 id="use-keyboard-shortcuts" tabindex="-1">Use keyboard shortcuts <a class="header-anchor" href="#use-keyboard-shortcuts" aria-label="Permalink to “Use keyboard shortcuts”">​</a></h3><p><img src="'+c+'" alt=""></p><blockquote><p>Inline formula: <code>$</code></p></blockquote><p><img src="'+s+'" alt=""></p><blockquote><p>Single-line formula: <code>Alt</code> + <code>$</code> / <code>Option</code> + <code>$</code></p></blockquote><p><img src="'+m+'" alt=""></p><blockquote><p>Multi-line formula in <code>\\eqnarray</code>: <code>Alt</code> + <code>&amp;</code> / <code>Option</code> + <code>&amp;</code></p></blockquote><p><img src="'+u+'" alt=""></p><blockquote><p>Multi-line formula in <code>\\align</code>: <code>Ctrl</code> + <code>$</code> / <code>Command</code> + <code>$</code> Shortcuts are active only with an English input method.</p></blockquote><h2 id="final-rendering" tabindex="-1">Final Rendering <a class="header-anchor" href="#final-rendering" aria-label="Permalink to “Final Rendering”">​</a></h2><ul><li><p>Inline formula <img src="'+p+'" alt=""></p></li><li><p>Single-line formula <img src="'+h+'" alt=""></p></li><li><p>Multi-line formula</p></li></ul><p>The two multi-line environments use different alignment styles:</p><p><img src="'+b+'" alt=""></p><blockquote><p>Multi-line formula in <code>eqnarray</code> format: <code>Alt</code> + <code>&amp;</code> / <code>Option</code> + <code>&amp;</code></p></blockquote><p><img src="'+f+'" alt=""></p><blockquote><p>Multi-line formula in <code>align</code> format: <code>Ctrl</code> + <code>$</code> / <code>Command</code> + <code>$</code></p></blockquote><h2 id="equation-numbering-and-referencing" tabindex="-1">Equation Numbering and Referencing <a class="header-anchor" href="#equation-numbering-and-referencing" aria-label="Permalink to “Equation Numbering and Referencing”">​</a></h2><h3 id="number-equations" tabindex="-1">Number equations <a class="header-anchor" href="#number-equations" aria-label="Permalink to “Number equations”">​</a></h3><p>In Math Mode, click <code>123</code> on the focus toolbar, or use the <code>\\eq-number</code> command to number formulas.</p><p><img src="'+g+'" alt=""></p><blockquote><p>Piecewise functions can be numbered as a whole formula, or line by line. If you select the formula and click <code>123</code>, the whole multi-line formula is numbered.</p></blockquote><p><img src="'+_+'" alt=""></p><blockquote><p><code>eqnarray</code> format supports only line-by-line numbering.</p></blockquote><p><img src="'+k+'" alt=""></p><blockquote><p><code>align</code> format supports only line-by-line numbering.</p></blockquote><h3 id="label-and-reference-equations" tabindex="-1">Label and reference equations <a class="header-anchor" href="#label-and-reference-equations" aria-label="Permalink to “Label and reference equations”">​</a></h3><p>You can label numbered equations in Liii STEM and reference them later in the same document.</p><p>For detailed steps, see <a href="/docs/guide-lines.html">Cross-Reference and Numbering</a>.</p>',44)])])}const $=o(q,[["render",M]]);export{T as __pageData,$ as default};
